import { useWallpaper, WALLPAPERS } from '../../contexts/WallpaperContext'

function WallpaperSettings() {
    const { wallpaper, setWallpaper } = useWallpaper()

    return (
        <div style={{ padding: '28px' }}>
            <h3 className="settings-section-title">Desktop Wallpaper</h3>
            <p style={{ fontSize: '13px', color: 'var(--text-secondary)', marginBottom: '24px', opacity: 0.8 }}>
                Choose a wallpaper for your dashboard background
            </p>

            <div className="wallpaper-grid">
                {WALLPAPERS.map(wp => (
                    <div
                        key={wp.id}
                        className={`wallpaper-thumb ${wallpaper.id === wp.id ? 'active' : ''}`}
                        onClick={() => setWallpaper(wp)}
                    >
                        <img
                            src={wp.thumbnail || wp.path}
                            alt={wp.name}
                            loading="lazy"
                            style={{
                                width: '100%', height: '100%',
                                objectFit: 'cover', display: 'block'
                            }}
                        />
                        <div className="wallpaper-thumb-label">
                            <span>{wp.name}</span>
                            {wallpaper.id === wp.id && (
                                <span className="wallpaper-check">✓</span>
                            )}
                        </div>
                    </div>
                ))}
            </div>

            <style>{`
                .wallpaper-grid {
                    display: grid;
                    grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
                    gap: 16px;
                }
            `}</style>
        </div>
    )
}

export default WallpaperSettings
